class Solution:
    def maxCount(self, banned, n, maxSum):
        banned_set = set(b for b in banned if 1 <= b <= n)
        def sum_of_smallest(k):
            total = 0
            cnt = 0
            i = 1
            while cnt < k and i <= n:
                if i not in banned_set:
                    total += i
                    cnt += 1
                i += 1
            return total if cnt == k else None
        lo, hi = 0, n
        best = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            s = sum_of_smallest(mid)
            if s is not None and s <= maxSum:
                best = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return best

