var maxCount = function(banned, n, maxSum) {
    const bannedSet = new Set(banned);
    let total = 0;
    let count = 0;
    for (let i = 1; i <= n; i++) {
        if (bannedSet.has(i)) continue;
        if (total + i > maxSum) break;
        total += i;
        count++;
    }
    return count;
};
